sections.code_example:
class Animal:
    def __init__(self, name):
        self.name = name

    def eat(self):
        print(self.name, "is eating.")

# Dog inherits from Animal
class Dog(Animal):
    def bark(self):
        print(self.name, "says: Woof!")

rex = Dog("Rex")
rex.eat()   # inherited from Animal
rex.bark()  # defined in Dog

class Animal:
    def __init__(self, name, sound):
        self.name = name
        self.sound = sound

    def speak(self):
        print(self.name, "says:", self.sound)

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name, "Woof")  # call Animal's __init__
        self.breed = breed              # Dog's own attribute

rex = Dog("Rex", "Labrador")
rex.speak()         # inherited + works with Dog's name
print(rex.breed)    # Dog's own attribute

