exercises.solution:
class Vehicle:
    def __init__(self, make, speed):
        self.make = make
        self.speed = speed

    def describe(self):
        print(f"Make: {self.make}, Speed: {self.speed}")

class Car(Vehicle):
    def __init__(self, make, speed):
        super().__init__(make, speed)
        self.doors = 4

car = Car("Toyota", 120)
car.describe()
print(car.doors)

